// Normalizza e pulisce l'output di Apify LinkedIn
const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // Skip se senza nome
  if (!d.firstName && !d.fullName) continue;

  const name = d.fullName || `${d.firstName || ''} ${d.lastName || ''}`.trim();
  const company = d.companyName || d.company || d.currentCompany || null;
  const role = d.jobTitle || d.headline || d.title || null;
  const linkedin_url = d.linkedInUrl || d.url || d.profileUrl || null;
  const location = d.location || d.city || null;
  const email = d.email || d.emailAddress || null;
  const phone = d.phone || d.phoneNumber || null;

  // Calcola score semplice
  let score = 0;
  if (email) score += 30;
  if (phone) score += 20;
  if (linkedin_url) score += 15;
  if (company) score += 15;
  if (role) score += 10;
  if (location) score += 10;

  results.push({
    json: {
      name,
      role,
      company,
      linkedin_url,
      email,
      phone,
      location,
      score: Math.min(score, 100),
      enrichment: {
        raw_headline: d.headline || null,
        connections: d.connectionsCount || null,
        industry: d.industry || null,
        summary: d.summary ? d.summary.slice(0, 200) : null,
      }
    }
  });
}

return results;

const response = $input.first().json;
console.log(`✅ LinkedIn: ${response.inserted} inseriti, ${response.received} ricevuti`);
return [{ json: { status: 'ok', ...response } }];
